use git2::{IndexAddOption, Repository};
use std::path::Path;

use super::models::{ConflictFile, ConflictReport};

/// Detect file-level conflicts between two branches using a read-only three-way merge.
///
/// Uses `merge_trees` to simulate a merge without modifying the working directory.
/// Returns a ConflictReport indicating whether conflicts exist and which files are affected.
pub fn detect_conflicts(
    repo_path: &Path,
    branch_a: &str,
    branch_b: &str,
) -> Result<ConflictReport, String> {
    let repo = Repository::open(repo_path).map_err(|e| format!("Failed to open repo: {}", e))?;

    // Resolve both branches to commits (using find_branch to handle `/` in names)
    let commit_a = super::resolve_branch_commit(&repo, branch_a)?;
    let commit_b = super::resolve_branch_commit(&repo, branch_b)?;

    // Find merge base (common ancestor)
    let merge_base = repo
        .merge_base(commit_a.id(), commit_b.id())
        .map_err(|e| format!("No common ancestor between '{}' and '{}': {}", branch_a, branch_b, e))?;

    let ancestor_commit = repo
        .find_commit(merge_base)
        .map_err(|e| format!("Failed to find merge base commit: {}", e))?;

    // Get trees from all three commits
    let ancestor_tree = ancestor_commit
        .tree()
        .map_err(|e| format!("Failed to get ancestor tree: {}", e))?;
    let tree_a = commit_a
        .tree()
        .map_err(|e| format!("Failed to get tree for '{}': {}", branch_a, e))?;
    let tree_b = commit_b
        .tree()
        .map_err(|e| format!("Failed to get tree for '{}': {}", branch_b, e))?;

    // Perform read-only three-way merge
    let index = repo
        .merge_trees(&ancestor_tree, &tree_a, &tree_b, None)
        .map_err(|e| format!("Failed to merge trees: {}", e))?;

    // Check for conflicts
    let has_conflicts = index.has_conflicts();
    let mut conflicting_files = Vec::new();

    if has_conflicts {
        let conflicts = index
            .conflicts()
            .map_err(|e| format!("Failed to iterate conflicts: {}", e))?;

        for entry in conflicts {
            let entry = entry.map_err(|e| format!("Failed to read conflict entry: {}", e))?;

            // Extract path from whichever side of the conflict has it
            let path = entry
                .our
                .as_ref()
                .or(entry.their.as_ref())
                .or(entry.ancestor.as_ref())
                .and_then(|e| String::from_utf8(e.path.clone()).ok());

            if let Some(path) = path {
                // Deduplicate (conflicts can appear multiple times per file)
                if !conflicting_files.iter().any(|f: &ConflictFile| f.path == path) {
                    conflicting_files.push(ConflictFile { path });
                }
            }
        }
    }

    Ok(ConflictReport {
        has_conflicts,
        conflicting_files,
        worktree_a: branch_a.to_string(),
        worktree_b: branch_b.to_string(),
    })
}

/// Perform a dry-run merge check using `git merge --no-commit --no-ff` via Command.
///
/// This is a more thorough conflict check than `detect_conflicts` because it
/// simulates the actual merge operation git would perform, including index-level
/// checks. After the check, any merge state is cleaned up via `git merge --abort`.
///
/// Returns a list of conflicting file paths, or an empty vec if clean.
pub fn dry_run_merge_check(
    repo_path: &Path,
    branch_name: &str,
) -> Result<Vec<String>, String> {
    use std::process::Command;

    // Run git merge --no-commit --no-ff to simulate the merge
    let output = Command::new("git")
        .args(["merge", "--no-commit", "--no-ff", branch_name])
        .current_dir(repo_path)
        .output()
        .map_err(|e| format!("Failed to run git merge dry-run: {}", e))?;

    let stdout = String::from_utf8_lossy(&output.stdout);
    let stderr = String::from_utf8_lossy(&output.stderr);

    if output.status.success() {
        // Merge succeeded without conflicts — abort to restore original state
        let _ = Command::new("git")
            .args(["merge", "--abort"])
            .current_dir(repo_path)
            .output();
        // Also try reset in case --abort doesn't work (merge was successful)
        let _ = Command::new("git")
            .args(["reset", "--merge"])
            .current_dir(repo_path)
            .output();
        return Ok(Vec::new());
    }

    // Parse conflicting files from the output
    let mut conflicting_files = Vec::new();
    let combined = format!("{}\n{}", stdout, stderr);
    for line in combined.lines() {
        // Git outputs "CONFLICT (content): Merge conflict in <file>"
        if let Some(rest) = line.strip_prefix("CONFLICT") {
            if let Some(idx) = rest.find("Merge conflict in ") {
                let file = rest[idx + "Merge conflict in ".len()..].trim();
                if !file.is_empty() {
                    conflicting_files.push(file.to_string());
                }
            }
            // Also handle "CONFLICT (modify/delete): <file> deleted in ..."
            // and other CONFLICT patterns where the file appears after ):
            else if let Some(after_paren) = rest.strip_prefix(" (") {
                if let Some(close_idx) = after_paren.find("): ") {
                    let after = &after_paren[close_idx + 3..];
                    // The file path is typically the first word
                    let file = after.split_whitespace().next().unwrap_or("");
                    if !file.is_empty() && !conflicting_files.contains(&file.to_string()) {
                        conflicting_files.push(file.to_string());
                    }
                }
            }
        }
    }

    // Abort the merge to restore original state
    let _ = Command::new("git")
        .args(["merge", "--abort"])
        .current_dir(repo_path)
        .output();

    Ok(conflicting_files)
}

/// Auto-commit all uncommitted changes in a worktree with a standard message.
///
/// Returns Ok(true) if changes were committed, Ok(false) if the worktree was clean.
pub fn auto_commit_worktree(worktree_path: &Path) -> Result<bool, String> {
    let repo =
        Repository::open(worktree_path).map_err(|e| format!("Failed to open repo: {}", e))?;

    // Check if there are any changes (modified, new, deleted)
    let statuses = repo
        .statuses(None)
        .map_err(|e| format!("Failed to get repo status: {}", e))?;

    let has_changes = statuses.iter().any(|s| {
        !s.status().is_ignored()
            && (s.status().intersects(
                git2::Status::WT_MODIFIED
                    | git2::Status::WT_NEW
                    | git2::Status::WT_DELETED
                    | git2::Status::WT_RENAMED
                    | git2::Status::WT_TYPECHANGE
                    | git2::Status::INDEX_MODIFIED
                    | git2::Status::INDEX_NEW
                    | git2::Status::INDEX_DELETED
                    | git2::Status::INDEX_RENAMED
                    | git2::Status::INDEX_TYPECHANGE,
            ))
    });

    if !has_changes {
        return Ok(false);
    }

    // Stage all changes
    let mut index = repo.index().map_err(|e| format!("Failed to get index: {}", e))?;
    index
        .add_all(["*"].iter(), IndexAddOption::DEFAULT, None)
        .map_err(|e| format!("Failed to stage changes: {}", e))?;
    index
        .write()
        .map_err(|e| format!("Failed to write index: {}", e))?;

    // Write tree from index
    let tree_id = index
        .write_tree()
        .map_err(|e| format!("Failed to write tree: {}", e))?;
    let tree = repo
        .find_tree(tree_id)
        .map_err(|e| format!("Failed to find tree: {}", e))?;

    // Create commit
    let sig = git2::Signature::now("WhaleCode", "whalecode@auto")
        .map_err(|e| format!("Failed to create signature: {}", e))?;
    let parent = repo
        .head()
        .map_err(|e| format!("Failed to get HEAD: {}", e))?
        .peel_to_commit()
        .map_err(|e| format!("Failed to peel HEAD: {}", e))?;

    repo.commit(
        Some("HEAD"),
        &sig,
        &sig,
        "whalecode: auto-commit task changes",
        &tree,
        &[&parent],
    )
    .map_err(|e| format!("Failed to create commit: {}", e))?;

    Ok(true)
}

